# ----------------------------
# TOTP (RFC 6238) implementation
# ----------------------------
def _totp(secret_b32: str, for_time: int = None, step: int = 30, digits: int = 6) -> str:
    if for_time is None:
        for_time = int(time.time())
    counter = int(for_time // step)
    secret_b32_padded = secret_b32.upper()
    pad = "=" * ((8 - (len(secret_b32_padded) % 8)) % 8)
    key = base64.b32decode(secret_b32_padded + pad, casefold=True)
    msg = counter.to_bytes(8, "big")
    h = hmac.new(key, msg, hashlib.sha1).digest()
    offset = h[-1] & 0x0F
    code_int = (int.from_bytes(h[offset:offset + 4], "big") & 0x7FFFFFFF) % (10 ** digits)
    return str(code_int).zfill(digits)

def _verify_totp(secret_b32: str, code: str, window: int = 1, step: int = 30, digits: int = 6) -> bool:
    code = (code or "").strip().replace(" ", "")
    if not code.isdigit() or len(code) != digits:
        return False
    now = int(time.time())
    for w in range(-window, window + 1):
        if hmac.compare_digest(_totp(secret_b32, now + (w * step), step=step, digits=digits), code):
            return True
    return False

