@app.route("/login", methods=["GET", "POST"])
def login():
    if request.method == "GET":
        return jsonify({
            "message": "POST username/password to login. Optionally include 'next'.",
            "fields": ["username", "password", "next(optional)"],
        })

    data = request.get_json(silent=True) or request.form
    username = (data.get("username") or "").strip()
    password = data.get("password") or ""
    next_url = data.get("next") or request.args.get("next") or url_for("protected")

    user = USERS.get(username)
    if not user or not _pbkdf2_verify_password(password, user["password_hash"]):
        return make_response(jsonify({"error": "Invalid credentials"}), 401)

    _issue_session(username)

    # Redirect to MFA verification page/endpoint.
    # MFA can also be verified "in background" by posting code to /verify-mfa?background=1
    if not _is_safe_url(next_url):
        next_url = url_for("protected")
    session["post_login_next"] = next_url

    return redirect(url_for("verify_mfa", next=next_url))

@app.route("/verify-mfa", methods=["GET", "POST"])
def verify_mfa():
    _sync_session_mfa_from_store()
    if not session.get("user") or not session.get("pwd_verified_at"):
        return redirect(url_for("login", next=request.args.get("next") or url_for("protected")))

    username = session["user"]
    user = USERS.get(username)
    if not user or not user.get("mfa_enabled"):
        session["mfa_verified"] = True
        session["mfa_verified_at"] = int(time.time())
        session["mfa_pending"] = False
        return redirect(session.get("post_login_next") or url_for("protected"))

    next_url = request.values.get("next") or session.get("post_login_next") or url_for("protected")
    if not _is_safe_url(next_url):
        next_url = url_for("protected")

    if request.method == "GET":
        return jsonify({
            "message": "POST MFA code to verify. You may set background=1 to verify asynchronously.",
            "fields": ["code", "background(optional)"],
            "mfa_pending": bool(session.get("mfa_pending")),
            "mfa_verified": bool(session.get("mfa_verified")),
            "next": next_url,
        })

    data = request.get_json(silent=True) or request.form
    code = (data.get("code") or "").strip()
    background = str(data.get("background") or request.args.get("background") or "").lower() in ("1", "true", "yes", "on")

    if background:
        cid = session.get("mfa_challenge_id")
        t = threading.Thread(target=_background_mfa_check, args=(username, code, cid), daemon=True)
        t.start()
        session["mfa_pending"] = True
        return jsonify({"status": "pending", "mfa_pending": True, "next": next_url})

    ok = _verify_totp(user["mfa_secret"], code)
    if not ok:
        session["mfa_verified"] = False
        session["mfa_verified_at"] = None
        session["mfa_pending"] = True
        return make_response(jsonify({"error": "Invalid MFA code", "mfa_pending": True}), 401)

    session["mfa_verified"] = True
    session["mfa_verified_at"] = int(time.time())
    session["mfa_pending"] = False
    return redirect(next_url)

